import{_ as a,c as n,o as s,a as t}from"./app.1e429f93.js";var e="/logotype.png";const m='{"title":"Getting started","description":"","frontmatter":{},"headers":[{"level":2,"title":"Installation","slug":"installation"},{"level":2,"title":"Using CDN","slug":"using-cdn"},{"level":2,"title":"Possible alternatives","slug":"possible-alternatives"},{"level":3,"title":"Model-based validation","slug":"model-based-validation"},{"level":3,"title":"Composable approach","slug":"composable-approach"},{"level":3,"title":"UI based","slug":"ui-based"},{"level":2,"title":"Getting Started","slug":"getting-started-1"},{"level":3,"title":"Alternative syntax (Composition API)","slug":"alternative-syntax-composition-api"},{"level":2,"title":"Sponsors","slug":"sponsors"}],"relativePath":"index.md","lastUpdated":1777558301325}',p={},o=t('<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-hidden="true">#</a></h1><p><img src="'+e+`" alt="Vuelidate Logotype"></p><p><strong>Vuelidate 2</strong> is a simple, but powerful, lightweight model-based validation for Vue.js 3 and 2.</p><p>Vuelidate is considered <em>model-based</em> because the validation rules are defined next to your data, and the validation tree structure matches the data model structure.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Vuelidate v2.0 supports both Vue 3.0 and Vue 2.x**</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-hidden="true">#</a></h2><p>Installing Vuelidate is straightforward, and can be done with your package manager of choice.</p><div class="language-bash"><pre><code><span class="token function">npm</span> <span class="token function">install</span> @vuelidate/core @vuelidate/validators

// OR

<span class="token function">yarn</span> <span class="token function">add</span> @vuelidate/core @vuelidate/validators
</code></pre></div><h2 id="using-cdn" tabindex="-1">Using CDN <a class="header-anchor" href="#using-cdn" aria-hidden="true">#</a></h2><p>Vuelidate also exposes a browser ready version, that you can use directly without a bundler. Add these imports to your browser:</p><div class="language-html"><pre><code><span class="token comment">&lt;!-- Vue--&gt;</span>
<span class="token comment">&lt;!--  For Vue 2 --&gt;</span>
<span class="token comment">&lt;!--  &lt;script src=&quot;https://cdn.jsdelivr.net/npm/vue@2&quot;&gt;&lt;/script&gt;--&gt;</span>
<span class="token comment">&lt;!--  &lt;script src=&quot;https://cdn.jsdelivr.net/npm/@vue/composition-api&quot;&gt;&lt;/script&gt;--&gt;</span>
<span class="token comment">&lt;!--  For Vue 3 --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://cdn.jsdelivr.net/npm/vue@3<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token comment">&lt;!--  Vuelidate --&gt;</span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://cdn.jsdelivr.net/npm/vue-demi<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://cdn.jsdelivr.net/npm/@vuelidate/core<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>https://cdn.jsdelivr.net/npm/@vuelidate/validators<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>Now you can access use <code>VueDemi</code>, <code>Vuelidate</code> and <code>VuelidateValidators</code> to build validations.</p><h2 id="possible-alternatives" tabindex="-1">Possible alternatives <a class="header-anchor" href="#possible-alternatives" aria-hidden="true">#</a></h2><p>Vuelidate is currently in LTS mode, so you may want to look at similar form libraries that are currently actively maintained.</p><h3 id="model-based-validation" tabindex="-1">Model-based validation <a class="header-anchor" href="#model-based-validation" aria-hidden="true">#</a></h3><ul><li><strong>Regle</strong>: \u2705 Headless form validation library for Vue.js [<a href="https://github.com/victorgarciaesgi/regle" target="_blank" rel="noopener noreferrer">Github</a>, <a href="https://reglejs.dev/" target="_blank" rel="noopener noreferrer">Docs</a>, <a href="https://reglejs.dev/introduction/migrate-from-vuelidate" target="_blank" rel="noopener noreferrer">Migration guide</a>] <ul><li>A validation library that use a similar API as Vuelidate&#39;s, with improved Typescript support, Nuxt integration and schema libraries (Zod, Valibot, Arktype)</li></ul></li></ul><h3 id="composable-approach" tabindex="-1">Composable approach <a class="header-anchor" href="#composable-approach" aria-hidden="true">#</a></h3><ul><li><strong>Vee-Validate</strong>: Painless Vue forms [<a href="https://github.com/logaretm/vee-validate/" target="_blank" rel="noopener noreferrer">Github</a>, <a href="https://vee-validate.logaretm.com/v4/" target="_blank" rel="noopener noreferrer">Docs</a>]</li></ul><h3 id="ui-based" tabindex="-1">UI based <a class="header-anchor" href="#ui-based" aria-hidden="true">#</a></h3><ul><li><strong>VueForm</strong>: Open-Source Form Framework for Vue [<a href="https://github.com/vueform/vueform" target="_blank" rel="noopener noreferrer">Github</a>, <a href="https://vueform.com/" target="_blank" rel="noopener noreferrer">Docs</a>]</li></ul><h2 id="getting-started-1" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started-1" aria-hidden="true">#</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>When used with Vue &lt;2.7, you need to install the <code>@vue/composition-api</code> plugin. You can learn how to do that <a href="https://github.com/vuejs/composition-api" target="_blank" rel="noopener noreferrer">here</a>. Once this is done, you can proceed with the below.</p></div><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">setup</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches this.firstName</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches this.lastName</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token comment">// Matches this.contact.email</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>Lets explain what happens here. We declare our local state with <code>data</code>, then we declare our validation rules with <code>validations</code>. Lastly, we activate Vuelidate inside <code>setup</code> by calling <code>useVuelidate</code>. Internally it will take the <code>validations</code> returned object and treat it as the validation rules. It will also take the whole component instance local state (including <code>data</code>, but also <code>computed</code>).</p><p>Notice how the the objects returned from <code>data</code> and <code>validations</code> have a matching structure.</p><div class="language-js"><div class="highlight-lines"><br><br><br><br><br><br><br><br><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><br><br><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><div class="highlighted">\xA0</div><br><br><br></div><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">setup</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">v$</span><span class="token operator">:</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches this.firstName</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches this.lastName</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token comment">// Matches this.contact.email</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h3 id="alternative-syntax-composition-api" tabindex="-1">Alternative syntax (Composition API) <a class="header-anchor" href="#alternative-syntax-composition-api" aria-hidden="true">#</a></h3><p>Vuelidate v2 also comes with support for Composition API. The above example can be translated into the composition API syntax.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> reactive <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span> <span class="token comment">// &quot;from &#39;@vue/composition-api&#39;&quot; if you are using Vue &lt;2.7</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> useVuelidate <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/core&#39;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">setup</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> state <span class="token operator">=</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
    <span class="token keyword">const</span> rules <span class="token operator">=</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">firstName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches state.firstName</span>
      <span class="token literal-property property">lastName</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Matches state.lastName</span>
      <span class="token literal-property property">contact</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">email</span><span class="token operator">:</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> email <span class="token punctuation">}</span> <span class="token comment">// Matches state.contact.email</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">const</span> v$ <span class="token operator">=</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span>rules<span class="token punctuation">,</span> state<span class="token punctuation">)</span>

    <span class="token keyword">return</span> <span class="token punctuation">{</span> state<span class="token punctuation">,</span> v$ <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>Now that validations are set up, we can check inside our template for errors by looking for example at the <code>firstName</code> property inside of the <code>v$</code> Vuelidate object. It will hold all the information and state of our <code>firstName</code> state&#39;s validation.</p><p>If <em>any</em> error is present, the <code>$errors</code> array property inside of <code>v$.firstName</code> will contain an object that describes each error for us to loop through.</p><p>Each object inside the <code>$errors</code> array will contain a few properties that allows us to dynamically build our error message.</p><p>An example of our <code>firstName</code> property being in an error state due to it being <code>required</code> would be:</p><div class="language-js"><pre><code><span class="token punctuation">{</span>
  <span class="token string-property property">&quot;$property&quot;</span><span class="token operator">:</span> <span class="token string">&quot;firstName&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;$validator&quot;</span><span class="token operator">:</span> <span class="token string">&quot;required&quot;</span><span class="token punctuation">,</span>
  <span class="token string-property property">&quot;$message&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Value is required&quot;</span><span class="token punctuation">,</span>
  <span class="token punctuation">[</span><span class="token operator">...</span><span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre></div><p>Now that we understand the basic content of the error objects, we can build our error messages in the template. This approach will dynamically cover any number of validators that were applied to our input.</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">:class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{ error: v$.firstName.$errors.length }<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>state.firstName<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>input-errors<span class="token punctuation">&quot;</span></span> <span class="token attr-name">v-for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error of v$.firstName.$errors<span class="token punctuation">&quot;</span></span> <span class="token attr-name">:key</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error.$uid<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>error-msg<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>{{ error.$message }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>That&#39;s it! Our validations are set and ready.</p><p>Head over to the <a href="./guide.html">Guide</a> page now for a more detailed guide on how to use Vuelidate.</p><h2 id="sponsors" tabindex="-1">Sponsors <a class="header-anchor" href="#sponsors" aria-hidden="true">#</a></h2><p align="center"><a href="https://getform.io" target="_blank"><img src="https://cdn.discordapp.com/attachments/1002927810710605875/1034915542596845728/getform.png" alt="Get Form" width="240px"></a></p><p align="center"><a href="https://www.storyblok.com/developers?utm_source=newsletter&amp;utm_medium=logo&amp;utm_campaign=vuejs-newsletter" target="_blank"><img src="https://a.storyblok.com/f/51376/3856x824/fea44d52a9/colored-full.png" alt="Storyblok" width="240px"></a></p><p align="center"><a href="https://www.vuemastery.com/" target="_blank"><img src="https://cdn.discordapp.com/attachments/258614093362102272/557267759130607630/Vue-Mastery-Big.png" alt="Vue Mastery logo" width="240px"></a></p>`,42),c=[o];function l(r,i,u,k,d,h){return s(),n("div",null,c)}var v=a(p,[["render",l]]);export{m as __pageData,v as default};
